const jobId = parseInt($input.first().json.query?.jobId) || 0;
if (!jobId) return [{ json: { jobId: 0 } }];
return [{ json: { jobId } }];

const body = $input.first().json.body || $input.first().json || {};
const jobTitle = (body.jobTitle || 'the position').substring(0, 100);
const candidateName = (body.candidateName || 'the candidate').substring(0, 100);
const questionNumber = parseInt(body.questionNumber) || 1;
const totalQuestions = parseInt(body.totalQuestions) || 10;
const language = body.language === 'ar' ? 'Arabic' : 'English';
const isFirst = !!body.isFirst;
const transcript = Array.isArray(body.transcript) ? body.transcript.slice(-4) : [];
const recentLines = transcript.map(t => `[${t.time||''}] ${t.speaker}: ${t.text}`).join('
');
const contextBlock = recentLines ? `
Recent conversation:
${recentLines}
` : '';
const prompt = `You are an AI interviewer conducting a structured job interview for the position of ${jobTitle} at Diyar United Company.
Candidate: ${candidateName}${contextBlock}

Generate interview question ${questionNumber} of ${totalQuestions}.
${isFirst ? 'This is the opening question — start with something to put the candidate at ease, like about their background or motivation.' : 'Build naturally on the conversation so far.'}
Language: ${language}

Return ONLY valid JSON:
{"question": "Your interview question here"}`;
return [{ json: { requestBody: JSON.stringify({ contents: [{ parts: [{ text: prompt }] }], generationConfig: { temperature: 0.7, maxOutputTokens: 400, responseMimeType: 'application/json' } }) } }];

const raw = $input.first().json;
let text = ((raw.candidates?.[0]?.content?.parts?.[0]?.text || '') || '').trim();
text = text.replace(/<think>[\s\S]*?<\/think>/gi, '').replace(/^```json\s*/i, '').replace(/```\s*$/i, '').trim();
let parsed = null;
try { parsed = JSON.parse(text); } catch(e) {
  const s = text.indexOf('{');
  const e2 = text.lastIndexOf('}');
  if (s >= 0 && e2 > s) try { parsed = JSON.parse(text.slice(s, e2+1)); } catch {}
}
const question = parsed?.question || parsed?.text || 'Could you tell me more about your relevant experience for this role?';
return [{ json: { question } }];

const body = $input.first().json.body || $input.first().json || {};
const jobTitle = (body.jobTitle || 'the position').substring(0, 100);
const candidateName = (body.candidateName || 'the candidate').substring(0, 100);
const duration = parseInt(body.durationSeconds || body.duration) || 0;
const minutes = Math.floor(duration/60);
const qaPairs = Array.isArray(body.qaPairs) ? body.qaPairs : (Array.isArray(body.transcript) ? body.transcript : []);
const customQuestions = Array.isArray(body.customQuestions) ? body.customQuestions : [];
const modelAnswerMap = {};
customQuestions.forEach((q, i) => { if (q.modelAnswer && q.modelAnswer.trim()) modelAnswerMap[i] = q.modelAnswer.trim(); });
const hasRubric = Object.keys(modelAnswerMap).length > 0;

const REQ_CATEGORIES = ['salary', 'iqama', 'notice', 'location'];
const requirementQs = [];
customQuestions.forEach((q, i) => { if (REQ_CATEGORIES.includes((q.category||'').toLowerCase()) && q.modelAnswer && q.modelAnswer.trim()) requirementQs.push({ index: i, category: (q.category||'').toLowerCase(), question: q.question || q.text || '', requirement: q.modelAnswer.trim() }); });
const hasRequirements = requirementQs.length > 0;

const noResponseCount = qaPairs.filter(p => {
  const a = (p.answer || '').trim().toLowerCase();
  return a === '(no response)' || a === '(no answer captured)' || a === '';
}).length;
const totalQ = qaPairs.length;

const qText = qaPairs.map((p, i) => {
  const ma = modelAnswerMap[i];
  const rubricLine = ma ? '\nExpected answer: ' + ma : '';
  return 'Q' + (i+1) + '. ' + (p.question||'') + rubricLine + '\nCandidate\'s answer: ' + ((p.answer||'(no answer captured)').substring(0,500));
}).join('\n\n');

const rubricInstruction = hasRubric ? '\nFor questions with an "Expected answer", score primarily on alignment with that rubric.' : '';

const requirementsBlock = hasRequirements ? '\n\nREQUIREMENTS TO EXTRACT:\n' + requirementQs.map(r => '- Q' + (r.index+1) + ' [' + r.category + ']: "' + r.question + '" -> Required: "' + r.requirement + '"').join('\n') + '\n\nFor each requirement above, extract the candidate\'s stated answer and determine if it meets the requirement (met: true/false).' : '';
const requirementsJson = hasRequirements ? ',\n  "requirements": [{"index": 1, "category": "salary", "question": "...", "requirement": "...", "extracted": "candidate stated value", "met": true, "note": "brief note"}]' : '';

const penaltyInstruction = noResponseCount === 0 ? '' :
  '\n\nPENALTY RULES (non-negotiable):\n' +
  '- Every "(no response)" or "(no answer captured)" answer scores 1-2 for that question — the candidate said nothing.\n' +
  (noResponseCount >= Math.ceil(totalQ / 2)
    ? '- The candidate failed to answer ' + noResponseCount + ' out of ' + totalQ + ' questions. Overall MUST be ≤ 3.\n'
    : '- The candidate failed to answer ' + noResponseCount + ' out of ' + totalQ + ' questions. Overall MUST be ≤ 5.\n') +
  '- Do NOT inflate scores based on one good answer. Score reflects the full interview, not cherry-picked moments.\n' +
  '- overall must equal the rounded average of communication + technical + confidence + cultureFit — do not independently estimate it.';

const prompt = 'You are a strict HR evaluator for a competitive role. Score honestly — unanswered questions are a serious red flag.\n\nPosition: ' + jobTitle + '\nCandidate: ' + candidateName + '\nDuration: ' + minutes + ' minute(s), ' + totalQ + ' questions asked\n\nQuestions and Answers:\n' + (qText||'No Q&A captured.') + rubricInstruction + requirementsBlock + penaltyInstruction + '\n\nRate 1-10 on each dimension. Return ONLY valid JSON:\n{\n  "communication": <score>,\n  "technical": <score>,\n  "confidence": <score>,\n  "cultureFit": <score>,\n  "overall": <average of above 4>,\n  "summary": "2-3 sentence honest performance summary",\n  "recommendation": "Hire / Consider / Don\'t Recommend — 1-2 sentence justification",\n  "perQuestion": [{"index": 1, "score": <score>, "feedback": "one sentence"}]' + requirementsJson + '\n}';

return [{ json: { requestBody: JSON.stringify({ contents: [{ parts: [{ text: prompt }] }], generationConfig: { temperature: 0.3, maxOutputTokens: 2048, responseMimeType: 'application/json' } }) } }];

const raw = $input.first().json;
let text = ((raw.candidates?.[0]?.content?.parts?.[0]?.text || '') || '').trim();
text = text.replace(/<think>[\s\S]*?<\/think>/gi,'').replace(/^```json\s*/i,'').replace(/```\s*$/i,'').trim();
function ex(t) { try { return JSON.parse(t); } catch {} const s=t.indexOf('{'),e=t.lastIndexOf('}'); if(s<0||e<s) return null; try { return JSON.parse(t.slice(s,e+1)); } catch { return null; } }
function c(v) { const n=parseFloat(v); return isNaN(n)?0:Math.min(10,Math.max(0,Math.round(n*10)/10)); }
const p = ex(text);
return [{ json: { communication: p?c(p.communication):0, technical: p?c(p.technical):0, confidence: p?c(p.confidence):0, cultureFit: p?c(p.cultureFit):0, overall: p?c(p.overall):0, summary: p?.summary||'Evaluation could not be generated.', recommendation: p?.recommendation||'', perQuestion: p?.perQuestion||[], requirements: p?.requirements||[] } }];

const body = $input.first().json.body;
const scores = body.scores || {};
const evalId = parseInt(body.evaluationId) || 0;
return [{
  json: {
    jobId: parseInt(body.jobId) || 0,
    candidateId: parseInt(body.candidateId) || 0,
    evaluationId: evalId > 0 ? evalId : null,
    candidateName: (body.candidateName || '').replace(/'/g, "''"),
    durationSeconds: parseInt(body.durationSeconds) || 0,
    transcript: JSON.stringify(body.transcript || []).replace(/'/g, "''"),
    qaPairs: JSON.stringify(body.transcript || []).replace(/'/g, "''"),
    communication: parseFloat(scores.communication) || 0,
    technical: parseFloat(scores.technical) || 0,
    confidence: parseFloat(scores.confidence) || 0,
    cultureFit: parseFloat(scores.cultureFit) || 0,
    overall: parseFloat(scores.overall) || 0,
    summary: (scores.summary || '').replace(/'/g, "''"),
    recommendation: (scores.recommendation || '').replace(/'/g, "''"),
    perQuestion: JSON.stringify(scores.perQuestion || []).replace(/'/g, "''"),
    recordingPath: (body.recordingPath || '').replace(/'/g, "''"),
    requirementsMatch: JSON.stringify(scores.requirements || body.requirementsMatch || []).replace(/'/g, "''")
  }
}];

const qs = $input.first().json.query || {};
const jobId = parseInt(qs.jobId) || 0;
if (!jobId) throw new Error('jobId required');
return [{ json: { jobId } }];

const body = $input.first().json.body || $input.first().json || {};
const candidateId   = parseInt(body.candidate_id);
const jobOpeningId  = parseInt(body.job_opening_id);
const questions     = Array.isArray(body.questions)   ? body.questions   : [];
const notes         = Array.isArray(body.notes)       ? body.notes       : [];
const generalNotes  = String(body.general_notes || '').substring(0, 20000);
const meeting       = body.meeting || {};

if (!candidateId  || isNaN(candidateId))  return [{ json: { error: true, message: 'candidate_id required' } }];
if (!jobOpeningId || isNaN(jobOpeningId)) return [{ json: { error: true, message: 'job_opening_id required' } }];

function pgEsc(s) { return s.replace(/'/g, "''"); }

const qJson  = pgEsc(JSON.stringify(questions));
const nJson  = pgEsc(JSON.stringify(notes));
const gNotes = pgEsc(generalNotes);
const mJson  = pgEsc(JSON.stringify(meeting));

const sql = `INSERT INTO candidate_prepared_questions (candidate_id, job_opening_id, questions, notes, general_notes, meeting, updated_at) VALUES (${candidateId}, ${jobOpeningId}, '${qJson}'::jsonb, '${nJson}'::jsonb, '${gNotes}', '${mJson}'::jsonb, NOW()) ON CONFLICT (candidate_id, job_opening_id) DO UPDATE SET questions = EXCLUDED.questions, notes = EXCLUDED.notes, general_notes = EXCLUDED.general_notes, meeting = EXCLUDED.meeting, updated_at = NOW() RETURNING id, candidate_id, job_opening_id, updated_at`;

return [{ json: { sql, ok: true } }];

const q = $input.first().json.query || {};
const candidateId  = parseInt(q.candidate_id);
const jobId        = parseInt(q.job_id);
if (!candidateId || !jobId) return [{ json: { error: true, message: 'candidate_id and job_id required' } }];
return [{ json: {
  sql: `SELECT id, candidate_id, job_opening_id, questions, notes, general_notes, meeting, updated_at FROM candidate_prepared_questions WHERE candidate_id = ${candidateId} AND job_opening_id = ${jobId} LIMIT 1`
} }];

const q = $input.first().json.query || {};
const jobId = parseInt(q.job_id);
if (!jobId) return [{ json: { error: true, message: 'job_id required' } }];
return [{ json: {
  sql: `SELECT cpq.id, cpq.candidate_id, cpq.job_opening_id, cpq.questions, cpq.general_notes, cpq.meeting, cpq.updated_at, c.candidate_name, c.email, jo.job_title, jo.department FROM candidate_prepared_questions cpq JOIN candidates c ON c.id = cpq.candidate_id JOIN job_openings jo ON jo.id = cpq.job_opening_id WHERE cpq.job_opening_id = ${jobId} ORDER BY cpq.updated_at DESC`
} }];
